      ru: ["2 ст. л. оливкового масла", "1 крупная луковица, мелко нарезанная", "1 красный болгарский перец, мелко нарезанный", "4 зубчика чеснока, мелко нарубленных", "1 ч. л. молотого тмина", "1 ч. л. сладкой паприки", "½ ч. л. копчёной паприки", "¼ ч. л. хлопьев чили", "2 банки по 400 г измельчённых помидоров", "1 ч. л. сахара", "соль и свежемолотый чёрный перец по вкусу", "6 яиц", "небольшая горсть свежей петрушки или кинзы, крупно нарубленных", "хрустящий хлеб или пита для подачи"],
      ar: ["2 ملعقة كبيرة زيت زيتون", "1 بصلة كبيرة، مقطعة ناعماً", "1 فلفل أحمر حلو، مقطع ناعماً", "4 فصوص ثوم، مفروم", "1 ملعقة صغيرة كمون مطحون", "1 ملعقة صغيرة فليفلة حلوة", "½ ملعقة صغيرة فليفلة مدخنة", "¼ ملعقة صغيرة رقائق الفلفل الحار", "2 علبة طماطم مهروسة (400 غ لكل علبة)", "1 ملعقة صغيرة سكر", "ملح وفلفل أسود مطحون طازجاً حسب الذوق", "6 بيضات", "حفنة صغيرة من البقدونس الطازج أو الكزبرة، مقطعة خشناً", "خبز مقرمش أو خبز بيتا للتقديم"],
      zh: ["橄榄油2汤匙", "大洋葱1个，细切", "红甜椒1个，细切", "大蒜4瓣，切末", "孜然粉1茶匙", "甜椒粉1茶匙", "烟熏辣椒粉½茶匙", "辣椒片¼茶匙", "碎番茄罐头2罐（每罐400克）", "糖1茶匙", "盐和现磨黑胡椒粉适量", "鸡蛋6个", "新鲜欧芹或香菜一小把，粗略切碎", "脆皮面包或皮塔饼，用于上桌"],
      ja: ["オリーブオイル大さじ2", "大きな玉ねぎ1個、細かく刻む", "赤いパプリカ1個、細かく刻む", "ニンニク4片、みじん切り", "クミンパウダー小さじ1", "スイートパプリカ小さじ1", "スモークパプリカ小さじ½", "チリフレーク小さじ¼", "ホールトマト缶（400g）2缶、つぶしたもの", "砂糖小さじ1", "塩と黒こしょう（挽きたて）適量", "卵6個", "新鮮なパセリまたはパクチー ひとつかみ、粗みじん切り", "クラスティパンまたはピタパン 盛り付け用"],
      tr: ["2 yemek kaşığı zeytinyağı", "1 büyük soğan, ince doğranmış", "1 kırmızı dolmalık biber, ince doğranmış", "4 diş sarımsak, kıyılmış", "1 çay kaşığı öğütülmüş kimyon", "1 çay kaşığı tatlı kırmızı biber", "½ çay kaşığı tütsülenmiş kırmızı biber", "¼ çay kaşığı pul biber", "2 x 400 g ezilmiş domates konservesi", "1 çay kaşığı şeker", "tuz ve taze çekilmiş siyah biber (tat için)", "6 yumurta", "bir avuç taze maydanoz veya kişniş, kabaca doğranmış", "servis için çıtır ekmek veya pide"],
      it: ["2 cucchiai di olio d'oliva", "1 grande cipolla, finemente tritata", "1 peperone rosso, finemente tritato", "4 spicchi d'aglio, tritati", "1 cucchiaino di cumino macinato", "1 cucchiaino di paprika dolce", "½ cucchiaino di paprika affumicata", "¼ cucchiaino di peperoncino secco in scaglie", "2 scatole da 400 g di pomodori pelati schiacciati", "1 cucchiaino di zucchero", "sale e pepe nero macinato fresco a piacere", "6 uova", "una manciata di prezzemolo fresco o coriandolo, tritati grossolanamente", "pane croccante o pita per servire"],
